import { useEditor, EditorContent } from "@tiptap/react";
import StarterKit from "@tiptap/starter-kit";
import TextAlign from "@tiptap/extension-text-align";
import Underline from "@tiptap/extension-underline";
import { Ic, ICONS } from "../components/UI";

export default function Editor({ t, toast }) {
  const [title, setTitle] = useState("Untitled Document");
  const [showTemplates, setShowTemplates] = useState(false);
  const [showCopilot, setShowCopilot] = useState(true);
  const [copilotTab, setCopilotTab] = useState("Chat");
  const [searchQuery, setSearchQuery] = useState("");

  // Data states
  const [templates, setTemplates] = useState([]);
  const [categories, setCategories] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState(null);

  // Dynamic Form states
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [formFields, setFormFields] = useState([]);
  const [formData, setFormData] = useState({});
  const [isRendering, setIsRendering] = useState(false);

  // AI Copilot States
  const [chats, setChats] = useState([
    { role: "assistant", content: "Hello! I'm your AI legal assistant. I can help you with drafting, reviewing, and research." }
  ]);
  const [chatInput, setChatInput] = useState("");
  const [isChatLoading, setIsChatLoading] = useState(false);

  // Initialize TipTap
  const editor = useEditor({
    extensions: [
      StarterKit,
      Underline,
      TextAlign.configure({ types: ['heading', 'paragraph'] }),
    ],
    content: "<p>Start drafting your legal document...</p>",
  });

  // Fetch Templates on mount
  useEffect(() => {
    fetch("http://localhost:8001/api/templates")
      .then(res => res.json())
      .then(data => {
        setTemplates(data);
        const uniqueCats = [...new Set(data.map(d => d.category))];
        setCategories(uniqueCats);
      })
      .catch(err => console.error("Error fetching templates:", err));
  }, []);

  const handleTemplateSelect = (template) => {
    setSelectedTemplate(template);
    try {
      const fields = JSON.parse(template.metadata_json || "[]");
      setFormFields(fields);
      setFormData({});
    } catch (e) {
      setFormFields([]);
    }
  };

  const handleRenderDraft = async () => {
    setIsRendering(true);
    try {
      const res = await fetch("http://localhost:8001/api/drafts/render", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          template_string: selectedTemplate.jinja_content,
          context: formData
        })
      });
      const data = await res.json();
      if (data.error) {
        toast(data.error, "error");
      } else {
        editor.commands.setContent(data.rendered_html);
        setShowTemplates(false);
        setSelectedTemplate(null);
        toast("Template loaded successfully!", "success");
      }
    } catch (err) {
      toast("Failed to render draft", "error");
    }
    setIsRendering(false);
  };

  const handleExportDocx = async () => {
    if (!editor) return;
    try {
      toast("Generating DOCX...", "info");
      const res = await fetch("http://localhost:8001/api/export/docx", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ html_content: editor.getHTML() })
      });

      const blob = await res.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `${title.replace(/\s+/g, '_')}.docx`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      toast("Document Exported!", "success");
    } catch (err) {
      toast("Export failed", "error");
    }
  };

  const insertAIContent = (text) => {
    if (editor) {
      editor.chain().focus().insertContent(text).run();
      toast("Clause inserted into document", "success");
    }
  };

  const handleChatSubmit = async (e) => {
    e.preventDefault();
    if (!chatInput.trim()) return;

    const newChat = { role: "user", content: chatInput };
    setChats(prev => [...prev, newChat]);
    setChatInput("");
    setIsChatLoading(true);

    try {
      const res = await fetch("http://localhost:8001/api/editor/copilot", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ prompt: newChat.content, document_context: editor ? editor.getText() : "" })
      });
      const data = await res.json();
      setChats(prev => [...prev, { role: "assistant", content: data.reply }]);
    } catch (err) {
      toast("Failed to connect to AI Copilot", "error");
      setChats(prev => [...prev, { role: "assistant", content: "Sorry, I encountered an error." }]);
    }
    setIsChatLoading(false);
  };

  return (
    <div style={{ display: "flex", height: "calc(100vh - 60px)", overflow: "hidden", background: t.bg }}>
      <style>{`
        /* TipTap Editor Styles */
        .ns-editor-wrapper {
          display: flex;
          flex-direction: column;
          flex: 1;
          height: 100%;
          background: ${t.name === "dark" ? "#121212" : "#f5f6f8"};
        }

        #ns-toolbar {
          border-bottom: 1px solid ${t.border};
          background: ${t.surface};
          padding: 12px 24px;
          display: flex;
          align-items: center;
          gap: 8px;
        }

        .tt-btn {
          background: transparent;
          border: none;
          padding: 6px;
          border-radius: 4px;
          cursor: pointer;
          color: ${t.sub};
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .tt-btn:hover { background: ${t.surfaceUp}; color: ${t.text}; }
        .tt-btn.is-active { background: ${t.surfaceUp}; color: ${t.blue}; }

        .ProseMirror {
          background: white;
          width: 816px;
          min-height: 1056px;
          padding: 96px;
          box-shadow: 0 4px 24px rgba(0,0,0,0.06);
          color: black;
          font-family: 'Times New Roman', serif;
          font-size: 16px;
          line-height: 1.6;
          outline: none;
          margin: 40px auto;
        }
        ${t.name === "dark" ? `
          .ProseMirror {
            background: #1e1e1e;
            color: #d4d4d4;
            box-shadow: 0 4px 24px rgba(0,0,0,0.5);
          }
        ` : ""}
        .ProseMirror p { margin-bottom: 1em; }
        .ProseMirror h1, .ProseMirror h2, .ProseMirror h3 { font-weight: bold; }
        .ProseMirror h3 { text-align: center; text-transform: uppercase; margin-bottom: 1.5em; font-size: 1.2em; }

        .editor-container {
          flex: 1;
          overflow-y: auto;
          display: flex;
          flex-direction: column;
        }

        /* Copilot Sidebar (Right Panel) */
        .ns-copilot {
          width: 380px;
          background: ${t.surface};
          border-left: 1px solid ${t.border};
          display: flex;
          flex-direction: column;
          flex-shrink: 0;
          box-shadow: -4px 0 24px rgba(0,0,0,0.05);
        }

        .ns-copilot-tab {
          flex: 1; padding: 12px; text-align: center; font-size: 13px; font-weight: 600;
          cursor: pointer; border-bottom: 2px solid transparent; color: ${t.sub};
        }
        .ns-copilot-tab.active {
          color: ${t.text}; border-bottom-color: ${t.blue};
        }

        .ns-chip {
          padding: 6px 14px; border-radius: 16px; border: 1px solid ${t.border};
          font-size: 12px; color: ${t.sub}; background: ${t.surfaceUp};
          cursor: pointer; white-space: nowrap; transition: all 0.2s;
        }
        .ns-chip:hover { border-color: ${t.blue}; color: ${t.blue}; background: ${t.blue}0a; }

        .ns-chat-scroll::-webkit-scrollbar { width: 4px; }
        .ns-chat-scroll::-webkit-scrollbar-thumb { background: ${t.border}; border-radius: 4px; }
      `}</style>

      {/* MAIN EDITOR AREA */}
      <div className="ns-editor-wrapper">
        {/* Top Header */}
        <div style={{ height: 64, borderBottom: `1px solid ${t.border}`, background: t.surface, display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 24px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
            <div style={{ width: 36, height: 36, background: t.surfaceUp, borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center", border: `1px solid ${t.border}` }}>
              <Ic d={ICONS.doc} size={18} color={t.sub} />
            </div>
            <div>
              <input 
                value={title} 
                onChange={e => setTitle(e.target.value)}
                style={{ background: "transparent", border: "none", fontSize: 18, fontWeight: 700, color: t.text, outline: "none", padding: 0, margin: "0 0 2px" }} 
              />
              <div style={{ fontSize: 12, color: t.sub }}>Legal Document • TipTap Engine</div>
            </div>
          </div>

          <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
            <button onClick={() => setShowTemplates(true)} style={{ display: "flex", alignItems: "center", gap: 8, background: t.surfaceUp, border: `1px solid ${t.border}`, color: t.text, padding: "8px 16px", borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: "pointer" }}>
              <Ic d={ICONS.grid} size={16} color={t.text} /> Templates
            </button>
            <button onClick={handleExportDocx} style={{ display: "flex", alignItems: "center", gap: 8, background: t.surfaceUp, border: `1px solid ${t.border}`, color: t.text, padding: "8px 16px", borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: "pointer" }}>
              <Ic d={ICONS.download} size={16} color={t.text} /> Export DOCX
            </button>
            <button style={{ display: "flex", alignItems: "center", gap: 8, background: t.blue, border: `1px solid ${t.blue}`, color: "white", padding: "8px 24px", borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: "pointer", boxShadow: "0 2px 8px rgba(13,110,253,0.3)" }}>
              <Ic d={ICONS.file} size={16} color="white" /> Save
            </button>

            <div style={{ width: 1, height: 24, background: t.border, margin: "0 4px" }}></div>

            <button 
              onClick={() => setShowCopilot(!showCopilot)}
              style={{ width: 40, height: 40, borderRadius: 8, background: showCopilot ? t.blue : t.surfaceUp, border: `1px solid ${showCopilot ? t.blue : t.border}`, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", transition: "all 0.2s" }}
            >
              <Ic d={ICONS.messageSquare} size={18} color={showCopilot ? "white" : t.blue} />
            </button>
          </div>
        </div>

        {/* TipTap Toolbar */}
        <div id="ns-toolbar">
          {editor && (
            <>
              <button onClick={() => editor.chain().focus().undo().run()} disabled={!editor.can().undo()} className="tt-btn"><Ic d={ICONS.arrowLeft} size={16}/></button>
              <button onClick={() => editor.chain().focus().redo().run()} disabled={!editor.can().redo()} className="tt-btn"><Ic d={ICONS.arrowRight} size={16}/></button>
              <div style={{ width: 1, height: 20, background: t.border, margin: "0 8px" }}></div>
              <button onClick={() => editor.chain().focus().toggleBold().run()} className={`tt-btn ${editor.isActive('bold') ? 'is-active' : ''}`}><b>B</b></button>
              <button onClick={() => editor.chain().focus().toggleItalic().run()} className={`tt-btn ${editor.isActive('italic') ? 'is-active' : ''}`}><i>I</i></button>
              <button onClick={() => editor.chain().focus().toggleUnderline().run()} className={`tt-btn ${editor.isActive('underline') ? 'is-active' : ''}`}><u>U</u></button>
              <button onClick={() => editor.chain().focus().toggleStrike().run()} className={`tt-btn ${editor.isActive('strike') ? 'is-active' : ''}`}><s>S</s></button>
              <div style={{ width: 1, height: 20, background: t.border, margin: "0 8px" }}></div>
              <button onClick={() => editor.chain().focus().setTextAlign('left').run()} className={`tt-btn ${editor.isActive({ textAlign: 'left' }) ? 'is-active' : ''}`}>Left</button>
              <button onClick={() => editor.chain().focus().setTextAlign('center').run()} className={`tt-btn ${editor.isActive({ textAlign: 'center' }) ? 'is-active' : ''}`}>Center</button>
              <button onClick={() => editor.chain().focus().setTextAlign('right').run()} className={`tt-btn ${editor.isActive({ textAlign: 'right' }) ? 'is-active' : ''}`}>Right</button>
              <button onClick={() => editor.chain().focus().setTextAlign('justify').run()} className={`tt-btn ${editor.isActive({ textAlign: 'justify' }) ? 'is-active' : ''}`}>Justify</button>
              <div style={{ width: 1, height: 20, background: t.border, margin: "0 8px" }}></div>
              <button onClick={() => editor.chain().focus().toggleHeading({ level: 1 }).run()} className={`tt-btn ${editor.isActive('heading', { level: 1 }) ? 'is-active' : ''}`}>H1</button>
              <button onClick={() => editor.chain().focus().toggleHeading({ level: 2 }).run()} className={`tt-btn ${editor.isActive('heading', { level: 2 }) ? 'is-active' : ''}`}>H2</button>
              <button onClick={() => editor.chain().focus().toggleHeading({ level: 3 }).run()} className={`tt-btn ${editor.isActive('heading', { level: 3 }) ? 'is-active' : ''}`}>H3</button>
              <div style={{ width: 1, height: 20, background: t.border, margin: "0 8px" }}></div>
              <button onClick={() => editor.chain().focus().toggleBulletList().run()} className={`tt-btn ${editor.isActive('bulletList') ? 'is-active' : ''}`}>Bullet</button>
              <button onClick={() => editor.chain().focus().toggleOrderedList().run()} className={`tt-btn ${editor.isActive('orderedList') ? 'is-active' : ''}`}>Numbered</button>
            </>
          )}
        </div>

        {/* Editor Area */}
        <div className="editor-container">
          <EditorContent editor={editor} />
        </div>
      </div>

      {/* RIGHT SIDEBAR: AI Copilot */}
      {showCopilot && (
        <div className="ns-copilot">
          <div style={{ padding: "16px 20px", borderBottom: `1px solid ${t.border}`, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              <div style={{ width: 32, height: 32, borderRadius: 8, background: t.blue, display: "flex", alignItems: "center", justifyContent: "center" }}>
                <Ic d={ICONS.book} size={16} color="white" />
              </div>
              <h3 style={{ margin: 0, fontSize: 16, fontWeight: 700, color: t.text }}>AI Assistant</h3>
            </div>
            <button onClick={() => setShowCopilot(false)} style={{ background: "transparent", border: "none", cursor: "pointer" }}>
              <Ic d={ICONS.x} size={20} color={t.sub} />
            </button>
          </div>

          <div style={{ display: "flex", padding: "0 20px", borderBottom: `1px solid ${t.border}` }}>
            {["Chat", "Notes", "Health"].map(tab => (
              <div 
                key={tab} 
                className={`ns-copilot-tab ${copilotTab === tab ? 'active' : ''}`}
                onClick={() => setCopilotTab(tab)}
              >
                {tab === "Chat" && <Ic d={ICONS.messageSquare} size={14} style={{ marginRight: 6, verticalAlign: "middle" }}/>}
                {tab === "Notes" && <Ic d={ICONS.file} size={14} style={{ marginRight: 6, verticalAlign: "middle" }}/>}
                {tab === "Health" && <Ic d={ICONS.shield} size={14} style={{ marginRight: 6, verticalAlign: "middle" }}/>}
                {tab}
              </div>
            ))}
          </div>

          {copilotTab === "Chat" && (
            <>
              <div className="ns-chat-scroll" style={{ flex: 1, overflowY: "auto", padding: 20, display: "flex", flexDirection: "column", gap: 16 }}>
                {chats.map((chat, idx) => (
                  <div key={idx} style={{ display: "flex", gap: 12, flexDirection: chat.role === "user" ? "row-reverse" : "row" }}>
                    {chat.role === "assistant" && (
                      <div style={{ width: 28, height: 28, borderRadius: "50%", background: t.blue, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                        <Ic d={ICONS.book} size={14} color="white" />
                      </div>
                    )}
                    <div style={{ 
                      background: chat.role === "user" ? t.blue : t.surfaceUp, 
                      color: chat.role === "user" ? "white" : t.text,
                      padding: "14px 16px", 
                      borderRadius: chat.role === "user" ? "16px 4px 16px 16px" : "4px 16px 16px 16px",
                      fontSize: 14,
                      lineHeight: 1.5,
                      border: chat.role === "assistant" ? `1px solid ${t.border}` : "none",
                      boxShadow: "0 2px 8px rgba(0,0,0,0.04)"
                    }}>
                      {chat.content}
                      {chat.role === "assistant" && idx > 0 && (
                        <button 
                          onClick={() => insertAIContent(chat.content)}
                          style={{ background: t.surface, border: `1px solid ${t.border}`, color: t.text, fontSize: 12, fontWeight: 600, marginTop: 12, padding: "6px 12px", borderRadius: 6, cursor: "pointer", display: "flex", alignItems: "center", gap: 6, width: "100%", justifyContent: "center" }}
                        >
                          <Ic d={ICONS.download} size={14} color={t.blue} /> Insert into Document
                        </button>
                      )}
                    </div>
                  </div>
                ))}
                {isChatLoading && (
                  <div style={{ display: "flex", gap: 12 }}>
                    <div style={{ width: 28, height: 28, borderRadius: "50%", background: t.blue, display: "flex", alignItems: "center", justifyContent: "center" }}>
                      <Ic d={ICONS.book} size={14} color="white" />
                    </div>
                    <div style={{ padding: "14px 16px", background: t.surfaceUp, borderRadius: "4px 16px 16px 16px", border: `1px solid ${t.border}` }}>
                      <div style={{ display: "flex", gap: 4 }}>
                        <span className="ns-dot"></span><span className="ns-dot" style={{animationDelay: "0.2s"}}></span><span className="ns-dot" style={{animationDelay: "0.4s"}}></span>
                      </div>
                    </div>
                  </div>
                )}
              </div>

              <div style={{ padding: 16, borderTop: `1px solid ${t.border}`, display: "flex", flexDirection: "column", gap: 12 }}>
                <div style={{ display: "flex", gap: 8, overflowX: "auto", paddingBottom: 4, scrollbarWidth: "none" }}>
                  <button className="ns-chip" onClick={() => setChatInput("Draft a jurisdiction clause")}>Draft Clause</button>
                  <button className="ns-chip" onClick={() => setChatInput("Review document for risks")}>Risk Review</button>
                  <button className="ns-chip" onClick={() => setChatInput("Fix legal citations")}>Fix Citations</button>
                </div>
                <form onSubmit={handleChatSubmit} style={{ display: "flex", background: t.bg, border: `1px solid ${t.border}`, borderRadius: 12, padding: "8px 12px", alignItems: "center" }}>
                  <input 
                    value={chatInput} 
                    onChange={e => setChatInput(e.target.value)}
                    placeholder="Ask anything about your document..." 
                    style={{ flex: 1, background: "transparent", border: "none", color: t.text, outline: "none", fontSize: 14 }}
                  />
                  <button type="submit" disabled={!chatInput.trim()} style={{ background: "transparent", border: "none", color: chatInput.trim() ? t.blue : t.border, cursor: chatInput.trim() ? "pointer" : "default", display: "flex" }}>
                    <Ic d={ICONS.send} size={18} />
                  </button>
                </form>
              </div>
            </>
          )}
        </div>
      )}

      {/* TEMPLATES MODAL */}
      {showTemplates && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", backdropFilter: "blur(4px)", zIndex: 10000, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ width: "100%", maxWidth: 800, background: t.surface, borderRadius: 16, boxShadow: "0 24px 48px rgba(0,0,0,0.2)", display: "flex", flexDirection: "column", maxHeight: "90vh" }}>

            <div style={{ padding: 24, borderBottom: `1px solid ${t.border}`, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                {selectedCategory ? (
                  <button onClick={() => {setSelectedCategory(null); setSelectedTemplate(null);}} style={{ padding: 8, background: "transparent", border: "none", cursor: "pointer", display: "flex", alignItems: "center" }}>
                    <Ic d={ICONS.chevronLeft} size={20} color={t.text} />
                  </button>
                ) : (
                  <div style={{ padding: 8, background: t.surfaceUp, borderRadius: 8, border: `1px solid ${t.border}` }}>
                    <Ic d={ICONS.doc} size={20} color={t.text} />
                  </div>
                )}
                <div>
                  <h2 style={{ margin: 0, fontSize: 20, fontWeight: 700 }}>
                    {selectedTemplate ? `Configure: ${selectedTemplate.title}` : selectedCategory ? selectedCategory : "Database Templates"}
                  </h2>
                  <div style={{ fontSize: 14, color: t.sub }}>Jinja2 Template Engine</div>
                </div>
              </div>
              <button onClick={() => {setShowTemplates(false); setSelectedCategory(null); setSelectedTemplate(null);}} style={{ background: "transparent", border: "none", cursor: "pointer" }}>
                <Ic d={ICONS.x} size={24} color={t.sub} />
              </button>
            </div>

            <div style={{ padding: 24, overflowY: "auto", minHeight: 400 }}>
              {!selectedCategory ? (
                // Category List
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
                  {categories.map((cat, i) => (
                    <button 
                      key={i} 
                      onClick={() => setSelectedCategory(cat)}
                      style={{ padding: 24, borderRadius: 12, border: `1px solid ${t.border}`, background: t.surface, display: "flex", flexDirection: "column", cursor: "pointer", textAlign: "left", transition: "all 0.2s" }}
                      onMouseEnter={e => { e.currentTarget.style.borderColor = t.blue; e.currentTarget.style.background = t.surfaceUp; }}
                      onMouseLeave={e => { e.currentTarget.style.borderColor = t.border; e.currentTarget.style.background = t.surface; }}
                    >
                      <h3 style={{ margin: "0 0 8px", fontSize: 18, fontWeight: 700, color: t.text }}>{cat}</h3>
                      <div style={{ fontSize: 13, color: t.sub, marginBottom: 16 }}>{templates.filter(t => t.category === cat).length} templates available</div>
                    </button>
                  ))}
                </div>
              ) : !selectedTemplate ? (
                // Templates List for Category
                <div style={{ display: "flex", flexDirection: "column", gap: 1 }}>
                  {templates.filter(t => t.category === selectedCategory).map((item, j) => (
                    <button 
                      key={j}
                      onClick={() => handleTemplateSelect(item)}
                      style={{ padding: "16px 8px", background: "transparent", border: "none", borderBottom: `1px solid ${t.border}`, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "space-between", textAlign: "left" }}
                    >
                      <div style={{ display: "flex", alignItems: "flex-start", gap: 16 }}>
                        <Ic d={ICONS.doc} size={20} color={t.sub} style={{ marginTop: 2 }} />
                        <div>
                          <div style={{ fontSize: 15, fontWeight: 600, color: t.text, marginBottom: 4 }}>{item.title}</div>
                          <div style={{ fontSize: 13, color: t.sub }}>{item.description}</div>
                        </div>
                      </div>
                      <Ic d={ICONS.chevronRight} size={18} color={t.sub} />
                    </button>
                  ))}
                </div>
              ) : (
                // Dynamic Fields Form
                <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
                  <div style={{ padding: 16, background: `${t.blue}11`, border: `1px solid ${t.blue}44`, borderRadius: 8, color: t.text, fontSize: 14 }}>
                    Please fill out the following variables required by the Jinja template. The backend will render the final document.
                  </div>

                  {formFields.length === 0 ? (
                    <div style={{ color: t.sub }}>No dynamic fields required for this template.</div>
                  ) : (
                    formFields.map((field, k) => (
                      <div key={k} style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                        <label style={{ fontSize: 14, fontWeight: 600, color: t.text }}>{field.label}</label>
                        <input 
                          type="text"
                          placeholder={`Enter ${field.label}`}
                          value={formData[field.name] || ""}
                          onChange={(e) => setFormData(prev => ({...prev, [field.name]: e.target.value}))}
                          style={{ padding: "12px 16px", borderRadius: 8, border: `1px solid ${t.border}`, background: t.bg, color: t.text, outline: "none" }}
                        />
                      </div>
                    ))
                  )}

                  <button 
                    onClick={handleRenderDraft}
                    disabled={isRendering}
                    style={{ marginTop: 16, padding: "14px", background: t.blue, color: "white", border: "none", borderRadius: 8, fontSize: 15, fontWeight: 700, cursor: isRendering ? "wait" : "pointer" }}
                  >
                    {isRendering ? "Rendering Engine..." : "Generate Draft Document"}
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
